#!/usr/bin/env bash
# Example deploy script — generated by configure.py (do not edit manually).
# cfn-deploy.sh is gitignored so your API key is never committed.
#
# Recommended path: run 'python3 configure.py' — it handles everything:
#   1. Creates the Lambda deployment bucket automatically
#   2. Builds and uploads the Lambda code
#   3. Deploys this CloudFormation stack
#
# Manual path (advanced):
#   The template expects the Lambda package at:
#     s3://<stack-name>-deploy-<aws-account-id>/lambda/package.zip
#   Create that bucket and upload src/ (zipped) to that key before running.

set -euo pipefail

aws cloudformation deploy \
  --template-file template.yaml \
  --stack-name ai-guard-monitor \
  --region "us-east-1" \
  --capabilities CAPABILITY_IAM CAPABILITY_NAMED_IAM \
  --parameter-overrides \
    AIGuardApiKey="YOUR_VISION_ONE_API_KEY" \
    AIGuardEndpoint="https://api.xdr.trendmicro.com/v3.0/aiSecurity/applyGuardrails" \
    AIGuardAppName="ai-guard-s3-monitor" \
    SourceBucketName="my-existing-source-bucket" \
    LogBucketName="my-ai-guard-logs" \
    NotificationEmail="" \
    SESVerifiedSender="" \
    MaxTextKB="500" \
    LambdaMemoryMB="512" \
    LambdaTimeoutSeconds="300" \
    LogRetentionDays="90" \
    EnableFileTagging="No" \
    EnableCloudWatchMonitoring="No"

echo "Stack deployed. Check Outputs tab in CloudFormation for next steps."
